from math import prod
from heapq import heappop, heappush
from sympy import prevprime, nextprime, factorint
def A291185(n):
    h, hset = [1], {1}
    while True:
        m = heappop(h)
        ps = factorint(m)
        if prod(p**(e+2)-p for p, e in ps.items())>=n*m*prod((p-1)**2 for p, e in ps.items()):
            return m
        for p in ps:
            if p == 2 or ps[prevprime(p)]>ps[p]:
                mp = m*p
                if mp not in hset:
                    heappush(h,mp)
                    hset.add(mp)
        mp = m*nextprime(max(ps.keys(),default=1))
        if mp not in hset:
            heappush(h,mp)
